import{_ as e,c as p}from"./app.0b00aae6.js";const n={},i=p(`<h1 id="_41-\u8BB2-\u4ECE\u5C0F\u5DE5\u5230\u4E13\u5BB6-\u804A\u804A\u6D4B\u8BD5\u6267\u884C\u73AF\u5883\u7684\u67B6\u6784\u8BBE\u8BA1-\u4E0B" tabindex="-1"><a class="header-anchor" href="#_41-\u8BB2-\u4ECE\u5C0F\u5DE5\u5230\u4E13\u5BB6-\u804A\u804A\u6D4B\u8BD5\u6267\u884C\u73AF\u5883\u7684\u67B6\u6784\u8BBE\u8BA1-\u4E0B" aria-hidden="true">#</a> 41 \u8BB2\uFF1A\u4ECE\u5C0F\u5DE5\u5230\u4E13\u5BB6\uFF1A\u804A\u804A\u6D4B\u8BD5\u6267\u884C\u73AF\u5883\u7684\u67B6\u6784\u8BBE\u8BA1\uFF08\u4E0B\uFF09</h1><p>\u4F60\u597D\uFF0C\u6211\u662F\u8339\u70B3\u665F\uFF0C\u4ECA\u5929\u6211\u548C\u4F60\u5206\u4EAB\u7684\u4E3B\u9898\u662F\u201C\u4ECE\u5C0F\u5DE5\u5230\u4E13\u5BB6\uFF1A\u804A\u804A\u6D4B\u8BD5\u6267\u884C\u73AF\u5883\u7684\u67B6\u6784\u8BBE\u8BA1\uFF08\u4E0B\uFF09\u201D\u3002</p><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4ECB\u7ECD\u4E86\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u7684\u6982\u5FF5\uFF0C\u4EE5\u53CA\u65E9\u671F\u7684\u548C\u7ECF\u5178\u7684\u4E24\u79CD\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u3002\u5728\u6587\u7AE0\u7684\u6700\u540E\uFF0C\u6211\u63D0\u5230\u7ECF\u5178\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u4E2D\u91C7\u7528\u7684 Selenium Grid \u65B9\u6848\uFF0C\u5728\u6D4B\u8BD5\u7528\u4F8B\u7684\u6570\u91CF\u6301\u7EED\u589E\u52A0\u7684\u60C5\u51B5\u4E0B\uFF0C\u4F1A\u5E26\u6765\u96C6\u7FA4\u6269\u5BB9\u3001Jenkins Job \u81C3\u80BF\u4E0D\u582A\u7B49\u8BF8\u591A\u95EE\u9898\uFF0C\u56E0\u6B64\u6211\u4EEC\u8003\u8651\u5C06 Selenium Grid \u8FC1\u79FB\u5230 Docker\uFF0C\u5E76\u4E14\u63D0\u4F9B\u4FBF\u4E8E Jenkins Job \u7BA1\u7406\u7684\u7EDF\u4E00\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u3002</p><p>\u6240\u4EE5\uFF0C\u4ECA\u5929\u7684\u8FD9\u7BC7\u6587\u7AE0\uFF0C\u6211\u5C31\u4F1A\u56F4\u7ED5\u8FD9\u4E9B\u74F6\u9888\u4EE5\u53CA\u5BF9\u5E94\u7684\u89E3\u51B3\u65B9\u6848\u6765\u5C55\u5F00\u3002</p><p><strong>\u57FA\u4E8E Docker \u5B9E\u73B0\u7684 Selenium Grid \u6D4B\u8BD5\u57FA\u7840\u67B6\u6784</strong></p><p>\u968F\u7740\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u7684\u5E7F\u6CDB\u4F7F\u7528\uFF0C\u4EE5\u53CA\u5927\u91CF\u7684\u6D4F\u89C8\u5668\u517C\u5BB9\u6027\u6D4B\u8BD5\u7684\u9700\u6C42\uFF0CSelenium Grid \u4E2D Node \u7684\u6570\u91CF\u4F1A\u53D8\u5F97\u8D8A\u6765\u8D8A\u5927\uFF0C\u4E5F\u5C31\u662F\u8BF4\u6211\u4EEC\u9700\u8981\u7EF4\u62A4\u7684 Selenium Node \u4F1A\u8D8A\u6765\u8D8A\u591A\u3002</p><p>\u5728 Node \u6570\u91CF\u53EA\u6709\u51E0\u5341\u53F0\u7684\u65F6\u5019\uFF0C\u901A\u8FC7\u4EBA\u5DE5\u7684\u65B9\u5F0F\u53BB\u5347\u7EA7 WebDriver\u3001\u66F4\u65B0\u6740\u6BD2\u8F6F\u4EF6\u3001\u5347\u7EA7\u6D4F\u89C8\u5668\u7248\u672C\uFF0C\u53EF\u80FD\u8FD8\u4E0D\u662F\u4EC0\u4E48\u5927\u95EE\u9898\u3002\u4F46\u662F\uFF0C\u5F53\u9700\u8981\u7EF4\u62A4\u7684 Node \u6570\u91CF\u8FBE\u5230\u51E0\u767E\u53F0\u751A\u81F3\u51E0\u5343\u53F0\u7684\u65F6\u5019\uFF0C\u8FD9\u4E9B Node \u7684\u7EF4\u62A4\u5DE5\u4F5C\u91CF\u5C31\u4F1A\u76F4\u7EBF\u4E0A\u5347\u3002\u867D\u7136\uFF0C\u4F60\u53EF\u4EE5\u901A\u8FC7\u4F20\u7EDF\u7684\u8FD0\u7EF4\u811A\u672C\u7BA1\u7406\u8FD9\u4E9B Node\uFF0C\u4F46\u7EF4\u62A4\u7684\u6210\u672C\u4F9D\u7136\u5C45\u9AD8\u4E0D\u4E0B\u3002</p><p>\u540C\u65F6\uFF0C\u968F\u7740\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\u7684\u6301\u7EED\u589E\u957F\uFF0CSelenium Node \u7684\u6570\u91CF\u4E5F\u5FC5\u7136\u4F1A\u4E0D\u65AD\u589E\u957F\uFF0C\u8FD9\u65F6\u5B89\u88C5\u90E8\u7F72\u65B0 Node \u7684\u5DE5\u4F5C\u91CF\u4E5F\u4F1A\u96BE\u4EE5\u60F3\u8C61\u3002\u56E0\u4E3A\uFF0C\u6BCF\u53F0 Node \u65E0\u8BBA\u662F\u91C7\u7528\u5B9E\u4F53\u673A\u8FD8\u662F\u865A\u62DF\u673A\uFF0C\u90FD\u4F1A\u7275\u6D89\u5230\u5B89\u88C5\u64CD\u4F5C\u7CFB\u7EDF\u3001\u6D4F\u89C8\u5668\u3001Java \u73AF\u5883\uFF0C\u4EE5\u53CA Selenium\u3002</p><p>\u800C\u76EE\u524D\u6D41\u884C\u7684 Docker \u5BB9\u5668\u6280\u672F\uFF0C\u7531\u4E8E\u5177\u6709\u66F4\u5FEB\u901F\u7684\u4EA4\u4ED8\u548C\u90E8\u7F72\u80FD\u529B\u3001\u66F4\u9AD8\u6548\u7684\u8D44\u6E90\u5229\u7528\uFF0C\u4EE5\u53CA\u66F4\u7B80\u5355\u7684\u66F4\u65B0\u7EF4\u62A4\u80FD\u529B\uFF0C\u4E5F\u5C31\u4F7F\u5F97 Docker \u76F8\u6BD4\u4E8E\u4F20\u7EDF\u865A\u62DF\u673A\u800C\u8A00\uFF0C\u66F4\u52A0\u5F97\u201C\u8F7B\u91CF\u7EA7\u201D\u3002</p><p>\u56E0\u6B64\uFF0C<strong>\u4E3A\u4E86\u964D\u4F4E Selenium Node \u7684\u7EF4\u62A4\u6210\u672C\uFF0C\u6211\u4EEC\u81EA\u7136\u800C\u7136\u5730\u60F3\u5230\u4E86\u76EE\u524D\u4E3B\u6D41\u7684\u5BB9\u5668\u6280\u672F\uFF0C\u4E5F\u5C31\u662F\u4F7F\u7528 Docker \u4EE3\u66FF\u539F\u672C\u7684\u865A\u62DF\u673A\u65B9\u6848\u3002</strong></p><p>\u57FA\u4E8E Docker \u7684 Selenium Grid\uFF0C\u53EF\u4EE5\u4ECE\u4E09\u4E2A\u65B9\u9762\u964D\u4F4E\u6211\u4EEC\u7EF4\u62A4\u6210\u672C\uFF1A</p><ol><li>\u7531\u4E8E Docker \u7684\u66F4\u65B0\u7EF4\u62A4\u66F4\u7B80\u5355\uFF0C\u4F7F\u5F97\u6211\u4EEC\u53EA\u8981\u7EF4\u62A4\u4E0D\u540C\u6D4F\u89C8\u5668\u7684\u4E0D\u540C\u955C\u50CF\u6587\u4EF6\u5373\u53EF\uFF0C\u800C\u65E0\u9700\u4E3A\u6BCF\u53F0\u673A\u5668\u5B89\u88C5\u6216\u8005\u5347\u7EA7\u5404\u79CD\u8F6F\u4EF6\uFF1B</li><li>Docker \u8F7B\u91CF\u7EA7\u7684\u7279\u70B9\uFF0C\u4F7F\u5F97 Node \u7684\u542F\u52A8\u548C\u6302\u8F7D\u6240\u9700\u65F6\u95F4\u5927\u5E45\u51CF\u5C11\uFF0C\u76F4\u63A5\u7531\u539F\u6765\u7684\u5206\u949F\u7EA7\u964D\u5230\u4E86\u79D2\u7EA7\uFF1B</li><li>Docker \u9AD8\u6548\u7684\u8D44\u6E90\u5229\u7528\uFF0C\u4F7F\u5F97\u540C\u6837\u7684\u786C\u4EF6\u8D44\u6E90\u53EF\u4EE5\u652F\u6301\u66F4\u591A\u7684 Node\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0C\u6211\u4EEC\u53EF\u4EE5\u5728\u4E0D\u989D\u5916\u6295\u5165\u786C\u4EF6\u8D44\u6E90\u7684\u60C5\u51B5\u4E0B\uFF0C\u6269\u5927 Selenium Grid \u7684\u5E76\u53D1\u6267\u884C\u80FD\u529B\u3002</li></ol><p>\u56E0\u6B64\uFF0C\u73B0\u5728\u5F88\u591A\u5927\u578B\u4E92\u8054\u7F51\u4F01\u4E1A\u7684\u6D4B\u8BD5\u6267\u884C\u73AF\u5883\u90FD\u5728\u5411 Docker \u8FC7\u6E21\u3002</p><p>\u800C\u5177\u4F53\u5982\u4F55\u57FA\u4E8E Docker \u642D\u5EFA\u4E00\u5957 Selenium Grid\uFF0C\u4F60\u53EF\u4EE5\u53C2\u8003\u6211\u5728\u7B2C 39 \u7BC7\u6587\u7AE0\u300A\u4ECE\u5C0F\u4F5C\u574A\u5230\u5DE5\u5382\uFF1A\u4EC0\u4E48\u662F Selenium Grid\uFF1F\u5982\u4F55\u642D\u5EFA Selenium Grid\uFF1F\u300B\u4E2D\u4ECB\u7ECD\u7684\u65B9\u6CD5\u3002\u7531\u6B64\u53EF\u89C1\uFF0C\u5C06\u539F\u672C\u57FA\u4E8E\u5B9E\u4F53\u673A\u6216\u8005\u865A\u62DF\u673A\u5B9E\u73B0\u7684 Selenium Grid \u6539\u8FDB\u6210\u4E3A\u57FA\u4E8E Docker \u5B9E\u73B0\u7684\u8FC7\u7A0B\u4E5F\u5F88\u7B80\u5355\u3001\u7075\u6D3B\u3002</p><p>\u5982\u56FE 1 \u6240\u793A\uFF0C\u5C31\u662F\u4E00\u4E2A\u57FA\u4E8E Docker \u5B9E\u73B0\u7684 Selenium Grid \u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u3002</p><p><img src="https://static001.geekbang.org/resource/image/56/75/56142f87923aa3c2e27746b91e2c0f75.png" alt="\u57FA\u4E8EDocker\u5B9E\u73B0\u7684Selenium Grid\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784"></p><p><strong>\u5F15\u5165\u7EDF\u4E00\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784</strong></p><p>\u5728\u5B9E\u9645\u7684\u4F7F\u7528\u8FC7\u7A0B\u4E2D\uFF0C\u57FA\u4E8E Docker \u7684 Selenium Grid \u4F7F\u5F97\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u7684\u5E76\u53D1\u6D4B\u8BD5\u80FD\u529B\u4E0D\u65AD\u589E\u5F3A\uFF0C\u4E5F\u56E0\u6B64\u4F1A\u6709\u5927\u91CF\u9879\u76EE\u7684\u5927\u91CF\u6D4B\u8BD5\u7528\u4F8B\u4F1A\u8FD0\u884C\u5728\u8FD9\u6837\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u4E4B\u4E0A\u3002</p><p>\u5F53\u9879\u76EE\u6570\u91CF\u4E0D\u591A\uFF0C\u6211\u4EEC\u53EF\u4EE5\u76F4\u63A5\u901A\u8FC7\u624B\u5DE5\u914D\u7F6E Jenkins Job\uFF0C\u5E76\u76F4\u63A5\u4F7F\u7528\u8FD9\u4E9B Job \u63A7\u5236\u6D4B\u8BD5\u7684\u53D1\u8D77\u548C\u6267\u884C\u3002\u4F46\u662F\uFF0C\u5F53\u9879\u76EE\u6570\u91CF\u975E\u5E38\u591A\u4E4B\u540E\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u7684\u6570\u91CF\u4E5F\u4F1A\u975E\u5E38\u591A\uFF0C\u8FD9\u65F6\u65B0\u7684\u95EE\u9898\u53C8\u6765\u4E86\uFF1A</p><ol><li>\u7BA1\u7406\u548C\u914D\u7F6E\u8FD9\u4E9B Jenkins Job \u7684\u5DE5\u4F5C\u91CF\u4F1A\u88AB\u4E0D\u65AD\u653E\u5927\uFF1B</li><li>\u8FD9\u4E9B Jenkins Job \u7684\u547D\u540D\u89C4\u8303\u3001\u914D\u7F6E\u89C4\u8303\u7B49\u4E5F\u5F88\u96BE\u5B9E\u73B0\u7EDF\u4E00\u7BA1\u7406\uFF0C\u4ECE\u800C\u5BFC\u81F4 Jenkins \u4E2D\u51FA\u73B0\u4E86\u5927\u91CF\u91CD\u590D\u548C\u4E0D\u89C4\u8303\u7684 Job\uFF1B</li><li>\u5F53\u9700\u8981\u53D1\u8D77\u6D4B\u8BD5\uFF0C\u6216\u8005\u65B0\u5EFA\u67D0\u4E9B\u6D4B\u8BD5\u7528\u4F8B\u65F6\uFF0C\u90FD\u8981\u76F4\u63A5\u64CD\u4F5C Jenkins Job\u3002\u800C\u8FD9\u4E2A\u8FC7\u7A0B\uFF0C\u5BF9\u4E8E\u4E0D\u4E86\u89E3\u8FD9\u4E9B Jenkins Job \u7EC6\u8282\u7684\u4EBA\uFF08\u6BD4\u5982\uFF0C\u65B0\u5458\u5DE5\u3001\u9879\u76EE\u7ECF\u7406\u3001\u4EA7\u54C1\u7ECF\u7406\uFF09\u6765\u8BF4\uFF0C\u8FD9\u79CD\u504F\u6280\u672F\u578B\u7684\u754C\u9762\u4F53\u9A8C\u5C31\u76F8\u5F53\u4E0D\u53CB\u597D\u4E86\u3002</li></ol><p>\u4E3A\u6B64\uFF0C\u6211\u4EEC\u4E3A\u4E86\u7BA1\u7406\u548C\u6267\u884C\u8FD9\u4E9B\u53D1\u8D77\u6D4B\u8BD5\u7684 Jenkins Job \u5B9E\u73B0\u4E86\u4E00\u4E2A GUI \u754C\u9762\u7CFB\u7EDF\u3002\u5728\u8FD9\u4E2A\u7CFB\u7EDF\u4E2D\uFF0C\u6211\u4EEC\u53EF\u4EE5\u57FA\u4E8E\u901A\u4FD7\u6613\u61C2\u7684\u754C\u9762\u64CD\u4F5C\uFF0C\u5B8C\u6210 Jenkins Job \u7684\u521B\u5EFA\u3001\u4FEE\u6539\u548C\u8C03\u7528\uFF0C\u5E76\u4E14\u53EF\u4EE5\u7BA1\u7406 Jenkins Job \u7684\u6267\u884C\u65E5\u5FD7\u4EE5\u53CA\u6D4B\u8BD5\u62A5\u544A\u3002</p><p>\u8FD9\uFF0C\u5176\u5B9E\u5C31\u662F\u7EDF\u4E00\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u7684\u96CF\u5F62\u4E86\u3002</p><p>\u6709\u4E86\u8FD9\u4E2A\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u7684\u96CF\u5F62\u540E\uFF0C\u6211\u4EEC\u9010\u6E10\u53D1\u73B0\u53EF\u4EE5\u5728\u8FD9\u4E2A\u5E73\u53F0\u4E0A\u505A\u66F4\u591A\u7684\u529F\u80FD\u6269\u5C55\uFF0C\u4E8E\u662F\u8FD9\u4E2A\u5E73\u53F0\u5C31\u9010\u6E10\u6F14\u53D8\u6210\u4E86\u6D4B\u8BD5\u6267\u884C\u7684\u7EDF\u4E00\u5165\u53E3\u3002</p><p>\u5728\u8FD9\u91CC\uFF0C\u6211\u5217\u4E3E\u4E86\u8FD9\u4E2A\u5E73\u53F0\u4E24\u4E2A\u6700\u4E3B\u8981\u7684\u529F\u80FD\u548C\u521B\u65B0\u8BBE\u8BA1\uFF0C\u5E0C\u671B\u53EF\u4EE5\u7ED9\u4F60\u4EE5\u53CA\u4F60\u6240\u5728\u516C\u53F8\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u5EFA\u8BBE\u5E26\u6765\u4E00\u4E9B\u542F\u53D1\u6027\u7684\u601D\u8003\u3002</p><p><strong>\u7B2C\u4E00\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u7684\u7248\u672C\u5316\u7BA1\u7406</strong>\u3002\u6211\u4EEC\u90FD\u77E5\u9053\uFF0C\u5E94\u7528\u7684\u5F00\u53D1\u6709\u7248\u672C\u63A7\u5236\u673A\u5236\uFF0C\u5373\uFF1A\u6BCF\u6B21\u63D0\u6D4B\u3001\u53D1\u5E03\u90FD\u6709\u5BF9\u5E94\u7684\u7248\u672C\u53F7\u3002\u6240\u4EE5\uFF0C\u4E3A\u4E86\u4F7F\u6D4B\u8BD5\u7528\u4F8B\u540C\u6837\u53EF\u8FFD\u6EAF\uFF0C\u4E5F\u5C31\u662F\u5E0C\u671B\u4E0D\u540C\u7248\u672C\u7684\u5F00\u53D1\u4EE3\u7801\u90FD\u80FD\u6709\u4E0E\u4E4B\u5BF9\u5E94\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u5F88\u591A\u5927\u578B\u4F01\u4E1A\u6216\u8005\u5927\u578B\u9879\u76EE\u90FD\u4F1A\u5F15\u5165\u6D4B\u8BD5\u7528\u4F8B\u7684\u7248\u672C\u5316\u7BA1\u7406\u3002\u6700\u7B80\u5355\u76F4\u63A5\u7684\u505A\u6CD5\u5C31\u662F\uFF0C\u91C7\u7528\u548C\u5F00\u53D1\u4E00\u81F4\u7684\u7248\u672C\u53F7\u3002</p><p>\u6BD4\u5982\uFF0C\u88AB\u6D4B\u5E94\u7528\u7684\u7248\u672C\u662F 1.0.1\uFF0C\u90A3\u4E48\u6D4B\u8BD5\u7528\u4F8B\u7684\u7248\u672C\u4E5F\u547D\u540D\u4E3A 1.0.1\u3002\u5728\u8FD9\u79CD\u60C5\u51B5\u4E0B\uFF0C\u5F53\u88AB\u6D4B\u5E94\u7528\u7248\u672C\u5347\u7EA7\u5230 1.0.2 \u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u4F1A\u76F4\u63A5\u751F\u6210\u4E00\u4E2A 1.0.2 \u7248\u672C\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF0C\u800C\u4E0D\u5E94\u8BE5\u76F4\u63A5\u4FEE\u6539 1.0.1 \u7248\u672C\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u8FD9\u6837\uFF0C\u5F53\u88AB\u6D4B\u73AF\u5883\u90E8\u7F72\u7684\u5E94\u7528\u7248\u672C\u662F 1.0.1 \u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u5C31\u9009\u62E9 1.0.1 \u7248\u672C\u7684\u6D4B\u8BD5\u7528\u4F8B\uFF1B\u800C\u5F53\u88AB\u6D4B\u73AF\u5883\u90E8\u7F72\u7684\u5E94\u7528\u7248\u672C\u662F 1.0.2 \u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u5C31\u76F8\u5E94\u5730\u9009\u62E9 1.0.2 \u7248\u672C\u7684\u6D4B\u8BD5\u7528\u4F8B\u3002</p><p>\u6240\u4EE5\uFF0C\u6211\u4EEC\u5C31\u5728\u8FD9\u4E2A\u7EDF\u4E00\u7684\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u4E2D\uFF0C\u5F15\u5165\u4E86\u8FD9\u79CD\u5F62\u5F0F\u7684\u6D4B\u8BD5\u7528\u4F8B\u7248\u672C\u63A7\u5236\u673A\u5236\uFF0C\u76F4\u63A5\u6839\u636E\u88AB\u6D4B\u5E94\u7528\u7684\u7248\u672C\u81EA\u52A8\u9009\u62E9\u5BF9\u5E94\u7684\u6D4B\u8BD5\u7528\u4F8B\u7248\u672C\u3002</p><p><strong>\u7B2C\u4E8C\uFF0C\u63D0\u4F9B\u57FA\u4E8E Restful API \u7684\u6D4B\u8BD5\u6267\u884C\u63A5\u53E3\u4F9B CI/CD \u4F7F\u7528</strong>\u3002\u8FD9\u6837\u505A\u7684\u539F\u56E0\u662F\uFF0C\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u7684\u7528\u6237\u4E0D\u4EC5\u4EC5\u662F\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u4EE5\u53CA\u76F8\u5173\u7684\u4EA7\u54C1\u7ECF\u7406\u3001\u9879\u76EE\u7ECF\u7406\uFF0C\u5F88\u591A\u65F6\u5019 CI/CD \u6D41\u6C34\u7EBF\u624D\u662F\u4E3B\u529B\u7528\u6237\u3002\u56E0\u4E3A\uFF0C\u5728 CI/CD \u6D41\u6C34\u7EBF\u4E2D\uFF0C\u6BCF\u4E2A\u9636\u6BB5\u90FD\u4F1A\u6709\u4E0D\u540C\u7684\u53D1\u8D77\u6D4B\u8BD5\u6267\u884C\u7684\u9700\u6C42\u3002</p><p>\u6211\u4EEC\u5C06\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u4E0E CI/CD \u6D41\u6C34\u7EBF\u96C6\u6210\u7684\u65E9\u671F\u5B9E\u73B0\u65B9\u6848\u662F\uFF0C\u76F4\u63A5\u5728 CI/CD \u6D41\u6C34\u7EBF\u7684\u811A\u672C\u4E2D\u786C\u7F16\u7801\u53D1\u8D77\u6D4B\u8BD5\u7684\u547D\u4EE4\u884C\u3002\u8FD9\u79CD\u65B9\u5F0F\u6700\u5927\u7684\u7F3A\u70B9\u5728\u4E8E\u7075\u6D3B\u6027\u5DEE\uFF1A</p><ul><li>\u5F53\u786C\u7F16\u7801\u7684\u547D\u4EE4\u884C\u53D1\u751F\u53D8\u5316\uFF0C\u6216\u8005\u5F15\u5165\u4E86\u65B0\u7684\u547D\u4EE4\u884C\u53C2\u6570\u7684\u65F6\u5019\uFF0CCI/CD \u6D41\u6C34\u7EBF\u7684\u811A\u672C\u4E5F\u8981\u4E00\u8D77\u8DDF\u7740\u4FEE\u6539\uFF1B</li><li>\u5F53\u5F15\u5165\u4E86\u65B0\u7684\u6D4B\u8BD5\u6846\u67B6\u65F6\uFF0C\u53D1\u8D77\u6D4B\u8BD5\u7684\u547D\u4EE4\u884C\u4E5F\u662F\u5168\u65B0\u7684\uFF0C\u90A3\u4E48 CI/CD \u6D41\u6C34\u7EBF\u7684\u811A\u672C\u4E5F\u5FC5\u987B\u88AB\u4E00\u8D77\u6539\u52A8\u3002</li></ul><p>\u56E0\u6B64\uFF0C\u4E3A\u4E86\u89E3\u51B3\u8026\u5408\u6027\u7684\u95EE\u9898\uFF0C\u6211\u4EEC\u5728\u8FD9\u4E2A\u7EDF\u4E00\u7684\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u4E0A\uFF0C\u63D0\u4F9B\u4E86\u57FA\u4E8E Restful API \u7684\u6D4B\u8BD5\u6267\u884C\u63A5\u53E3\u3002\u4EFB\u4F55\u65F6\u5019\u4F60\u90FD\u53EF\u4EE5\u901A\u8FC7\u4E00\u4E2A\u6807\u51C6\u7684 Restful API \u53D1\u8D77\u6D4B\u8BD5\uFF0CCI/CD \u6D41\u6C34\u7EBF\u7684\u811A\u672C\u4E5F\u65E0\u987B\u518D\u77E5\u9053\u53D1\u8D77\u6D4B\u8BD5\u7684\u547D\u4EE4\u884C\u7684\u5177\u4F53\u7EC6\u8282\u4E86\uFF0C\u53EA\u8981\u8C03\u7528\u7EDF\u4E00\u7684 Restful API \u5373\u53EF\u3002</p><p>\u5982\u56FE 2 \u6240\u793A\uFF0C\u5C31\u662F\u5F15\u5165\u4E86\u7EDF\u4E00\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u3002</p><p><img src="https://static001.geekbang.org/resource/image/40/43/40be3cb1a925bbcf24c2a710f0711443.png" alt="\u5F15\u5165\u7EDF\u4E00\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784
"></p><p><strong>\u57FA\u4E8E Jenkins \u96C6\u7FA4\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784</strong></p><p>\u8FD9\u4E2A\u5F15\u5165\u4E86\u7EDF\u4E00\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\uFF0C\u770B\u4F3C\u5DF2\u7ECF\u5F88\u5B8C\u7F8E\u4E86\u3002\u4F46\u662F\uFF0C\u968F\u7740\u6D4B\u8BD5\u9700\u6C42\u7684\u7EE7\u7EED\u589E\u957F\uFF0C\u53C8\u6D8C\u73B0\u51FA\u4E86\u65B0\u7684\u95EE\u9898\uFF1A\u5355\u4E2A Jenkins \u6210\u4E86\u6574\u4E2A\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u7684\u74F6\u9888\u8282\u70B9\u3002\u56E0\u4E3A\uFF0C\u6765\u81EA\u4E8E\u7EDF\u4E00\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u7684\u5927\u91CF\u6D4B\u8BD5\u8BF7\u6C42\uFF0C\u4F1A\u5728 Jenkins \u4E0A\u6392\u961F\u7B49\u5F85\u6267\u884C\uFF0C\u800C\u540E\u7AEF\u771F\u6B63\u6267\u884C\u6D4B\u8BD5\u7528\u4F8B\u7684 Selenium Grid \u4E2D\u5F88\u591A Node \u5904\u4E8E\u7A7A\u95F2\u72B6\u6001\u3002</p><p>\u4E3A\u6B64\uFF0C\u5C06\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u4E2D\u7684\u5355\u4E2A Jenkins \u6269\u5C55\u4E3A Jenkins \u96C6\u7FA4\u7684\u65B9\u6848\u5C31\u52BF\u5728\u5FC5\u884C\u4E86\u3002\u5982\u56FE 3 \u6240\u793A\uFF0C\u5C31\u662F\u57FA\u4E8E Jenkins \u96C6\u7FA4\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u3002</p><p><img src="https://static001.geekbang.org/resource/image/db/f5/db974bd10bf6146c2ad1afbdb310ccf5.png" alt="\u57FA\u4E8EJenkins\u96C6\u7FA4\u7684\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784"></p><p>\u56E0\u4E3A Jenkins \u96C6\u7FA4\u4E2D\u5305\u542B\u4E86\u591A\u4E2A\u53EF\u4EE5\u4E00\u8D77\u5DE5\u4F5C\u7684 Jenkins Slave\uFF0C\u6240\u4EE5\u5927\u91CF\u6D4B\u8BD5\u8BF7\u6C42\u6392\u961F\u7684\u73B0\u8C61\u5C31\u518D\u4E5F\u4E0D\u4F1A\u51FA\u73B0\u4E86\u3002</p><p>\u800C\u8FD9\u4E2A\u5347\u7EA7\u5230 Jenkins \u96C6\u7FA4\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u5BF9\u4E8E Jenkins \u96C6\u7FA4\u4E2D Slave \u7684\u6570\u91CF\u5230\u5E95\u591A\u5C11\u624D\u5408\u9002\u5E76\u6CA1\u6709\u5B9A\u8BBA\u3002\u4E00\u822C\u7684\u505A\u6CD5\u662F\uFF0C\u6839\u636E\u6D4B\u8BD5\u9AD8\u5CF0\u65F6\u6BB5 Jenkins \u4E2D\u7684\u6392\u961F\u6570\u91CF\u6765\u9884\u4F30\u4E00\u4E2A\u503C\u3002\u901A\u5E38\u6700\u5F00\u59CB\u7684\u65F6\u5019\uFF0C\u6211\u4EEC\u4F1A\u4F7F\u7528 4 \u4E2A Slave \u8282\u70B9\uFF0C\u7136\u540E\u89C2\u5BDF\u9AD8\u5CF0\u65F6\u6BB5\u7684\u6392\u961F\u60C5\u51B5\uFF0C\u5982\u679C\u8FD8\u662F\u6709\u5927\u91CF\u6392\u961F\uFF0C\u5C31\u7EE7\u7EED\u589E\u52A0 Slave \u8282\u70B9\u3002</p><p><strong>\u6D4B\u8BD5\u8D1F\u8F7D\u81EA\u9002\u5E94\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784</strong></p><p>\u5F15\u5165\u4E86 Jenkins \u96C6\u7FA4\u540E\uFF0C\u6574\u4E2A\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u5DF2\u7ECF\u5F88\u6210\u719F\u4E86\uFF0C\u57FA\u672C\u4E0A\u53EF\u4EE5\u6EE1\u8DB3\u7EDD\u5927\u591A\u6570\u7684\u6D4B\u8BD5\u573A\u666F\u4E86\u3002\u4F46\u662F\uFF0C\u8FD8\u6709\u4E00\u4E2A\u95EE\u9898\u4E00\u76F4\u6CA1\u6709\u5F97\u5230\u89E3\u51B3\uFF0C\u90A3\u5C31\u662F\uFF1ASelenium Grid \u4E2D Node \u7684\u6570\u91CF\u5230\u5E95\u591A\u5C11\u624D\u5408\u9002\uFF1F</p><ul><li>\u5982\u679C Node \u6570\u91CF\u5C11\u4E86\uFF0C\u90A3\u4E48\u5F53\u96C6\u4E2D\u53D1\u8D77\u6D4B\u8BD5\u7684\u65F6\u5019\uFF0C\u5C31\u4F1A\u7531\u4E8E Node \u4E0D\u591F\u7528\u800C\u9020\u6210\u6D4B\u8BD5\u7528\u4F8B\u7684\u6392\u961F\u7B49\u5F85\uFF0C\u8FD9\u79CD\u573A\u666F\u5728\u4E92\u8054\u7F51\u4F01\u4E1A\u4E2D\u5F88\u5E38\u89C1\uFF1B</li><li>\u800C\u5982\u679C Node \u6570\u91CF\u591A\u4E86\uFF0C\u867D\u7136\u53EF\u4EE5\u89E3\u51B3\u6D4B\u8BD5\u9AD8\u5CF0\u65F6\u6BB5\u7684\u6027\u80FD\u74F6\u9888\u95EE\u9898\uFF0C\u4F46\u662F\u53C8\u4F1A\u9020\u6210\u7A7A\u95F2\u65F6\u6BB5\u7684\u8BA1\u7B97\u8D44\u6E90\u6D6A\u8D39\u95EE\u9898\u3002\u5F53\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u642D\u5EFA\u5728\u6309\u4F7F\u7528\u4ED8\u8D39\u7684\u4E91\u7AEF\u65F6\uFF0C\u8BA1\u7B97\u8D44\u6E90\u7684\u6D6A\u8D39\u5C31\u662F\u8D44\u91D1\u6D6A\u8D39\u4E86\u3002</li></ul><p>\u4E3A\u4E86\u89E3\u51B3\u8FD9\u79CD\u6D4B\u8BD5\u8D1F\u8F7D\u4E0D\u5747\u8861\u7684\u95EE\u9898\uFF0CSelenium Grid \u7684\u81EA\u52A8\u6269\u5BB9\u548C\u6536\u7F29\u6280\u672F\u5C31\u5E94\u8FD0\u800C\u751F\u4E86\u3002</p><p>Selenium Grid \u7684\u81EA\u52A8\u6269\u5BB9\u548C\u6536\u7F29\u6280\u672F\u7684\u6838\u5FC3\u601D\u60F3\u662F\uFF0C\u901A\u8FC7\u5355\u4F4D\u65F6\u95F4\u5185\u7684\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\uFF0C\u4EE5\u53CA\u671F\u671B\u6267\u884C\u5B8C\u6240\u6709\u6D4B\u8BD5\u7684\u65F6\u95F4\uFF0C\u6765\u52A8\u6001\u8BA1\u7B97\u5F97\u5230\u6240\u9700\u7684 Node \u7C7B\u578B\u548C\u6570\u91CF\uFF0C\u7136\u540E\u518D\u57FA\u4E8E Docker \u5BB9\u5668\u5FEB\u901F\u6DFB\u52A0\u65B0\u7684 Node \u5230 Selenium Grid \u4E2D\uFF1B\u800C\u7A7A\u95F2\u65F6\u6BB5\u5219\u53BB\u76D1\u63A7\u54EA\u4E9B Node \u5728\u6307\u5B9A\u65F6\u95F4\u957F\u77ED\u5185\u6CA1\u6709\u88AB\u4F7F\u7528\uFF0C\u5E76\u52A8\u6001\u5730\u56DE\u6536\u8FD9\u4E9B Node \u4EE5\u91CA\u653E\u7CFB\u7EDF\u8D44\u6E90\u3002</p><p>\u901A\u5E38\u60C5\u51B5\u4E0B\uFF0C\u51E0\u767E\u4E43\u81F3\u4E0A\u5343\u53F0 Node \u7684\u6269\u5BB9\u90FD\u53EF\u4EE5\u5728\u51E0\u5206\u949F\u5185\u5B8C\u6210\uFF0CNode \u7684\u9500\u6BC1\u4E0E\u56DE\u6536\u7684\u901F\u5EA6\u540C\u6837\u975E\u5E38\u5FEB\u3002</p><p>\u81F3\u6B64\uFF0C\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u5DF2\u7ECF\u6F14\u53D8\u5F97\u5F88\u5148\u8FDB\u4E86\uFF0C\u57FA\u672C\u53EF\u4EE5\u6EE1\u8DB3\u5927\u578B\u7535\u5546\u7684\u6D4B\u8BD5\u6267\u884C\u9700\u6C42\u4E86\u3002\u6D4B\u8BD5\u8D1F\u8F7D\u81EA\u9002\u5E94\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\uFF0C\u5177\u4F53\u5982\u56FE 4 \u6240\u793A\u3002</p><p><img src="https://static001.geekbang.org/resource/image/da/a4/daeb20ac9fee266ecbabbfadfa2305a4.png" alt="\u6D4B\u8BD5\u8D1F\u8F7D\u81EA\u9002\u5E94\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784"></p><p><strong>\u5982\u4F55\u9009\u62E9\u9002\u5408\u81EA\u5DF1\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\uFF1F</strong></p><p>\u73B0\u5728\uFF0C\u6211\u5DF2\u7ECF\u4ECB\u7ECD\u5B8C\u4E86\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u7684\u6F14\u8FDB\uFF0C\u4EE5\u53CA\u5176\u4E2D\u5404\u9636\u6BB5\u4E3B\u8981\u7684\u67B6\u6784\u8BBE\u8BA1\u601D\u8DEF\uFF0C\u90A3\u4E48\u5BF9\u4E8E\u4F01\u4E1A\u6765\u8BF4\uFF0C\u5E94\u5F53\u5982\u4F55\u9009\u62E9\u6700\u9002\u5408\u81EA\u5DF1\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u5462\uFF1F</p><p>\u5176\u5B9E\uFF0C\u5BF9\u4E8E\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u7684\u5EFA\u8BBE\uFF0C\u6211\u4EEC\u5207\u5FCC\u4E0D\u8981\u4E3A\u4E86\u8FFD\u6C42\u65B0\u6280\u672F\u800C\u4F7F\u7528\u65B0\u6280\u672F\uFF0C\u800C\u662F\u5E94\u8BE5\u6839\u636E\u4F01\u4E1A\u76EE\u524D\u5728\u6D4B\u8BD5\u6267\u884C\u73AF\u5883\u4E0A\u7684\u75DB\u70B9\uFF0C\u6765\u6709\u9488\u5BF9\u6027\u5730\u9009\u62E9\u4E0E\u5B9A\u5236\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u3002</p><p>\u6BD4\u5982\uFF0C\u4F60\u6240\u5728\u7684\u4F01\u4E1A\u5982\u679C\u89C4\u6A21\u4E0D\u662F\u5F88\u5927\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u6267\u884C\u7684\u603B\u6570\u91CF\u76F8\u5BF9\u8F83\u5C11\uFF0C\u800C\u4E14\u77ED\u671F\u5185\u4E5F\u4E0D\u4F1A\u6709\u5927\u53D8\u5316\u7684\u60C5\u51B5\uFF0C\u90A3\u4E48\u4F60\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u5B8C\u5168\u5C31\u53EF\u4EE5\u91C7\u7528\u7ECF\u5178\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\uFF0C\u800C\u6CA1\u5FC5\u8981\u5F15\u5165 Docker \u548C\u52A8\u6001\u6269\u5BB9\u7B49\u6280\u672F\u3002</p><p>\u518D\u6BD4\u5982\uFF0C\u5982\u679C\u662F\u5927\u578B\u4F01\u4E1A\uFF0C\u6D4B\u8BD5\u7528\u4F8B\u6570\u91CF\u5E9E\u5927\uFF0C\u540C\u65F6\u8FD8\u4F1A\u5B58\u5728\u53D1\u5E03\u65F6\u6BB5\u5927\u91CF\u6D4B\u8BD5\u8BF7\u6C42\u96C6\u4E2D\u5230\u6765\u7684\u60C5\u51B5\uFF0C\u90A3\u4E48\u6B64\u65F6\u5C31\u4E0D\u5F97\u4E0D\u91C7\u7528 Selenium Gird \u52A8\u6001\u6269\u5BB9\u7684\u67B6\u6784\u4E86\u3002\u800C\u4E00\u65E6\u8981\u4F7F\u7528\u52A8\u6001\u6269\u5BB9\uFF0C\u90A3\u4E48\u52BF\u5FC5\u4F60\u7684 Node \u5C31\u5FC5\u987B\u505A\u5230 Docker \u5BB9\u5668\u5316\uFF0C\u5426\u5219\u65E0\u6CD5\u5B8C\u5168\u53D1\u6325\u81EA\u52A8\u6269\u5BB9\u7684\u4F18\u52BF\u3002</p><p>\u6240\u4EE5\u8BF4\uFF0C\u91C7\u7528\u4EC0\u4E48\u6837\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u4E0D\u662F\u7531\u6280\u672F\u672C\u8EAB\u51B3\u5B9A\u7684\uFF0C\u800C\u662F\u7531\u6D4B\u8BD5\u9700\u6C42\u63A8\u52A8\u7684\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u5728\u4ECA\u5929\u8FD9\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4ECE\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u6F14\u8FDB\u7684\u89C6\u89D2\uFF0C\u548C\u4F60\u5206\u4EAB\u4E86\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u53D1\u5C55\u7684\u524D\u4E16\u4ECA\u751F\u3002</p><p>\u9996\u5148\uFF0C\u4E3A\u4E86\u964D\u4F4E\u6D4B\u8BD5\u7528\u4F8B\u8FC7\u591A\u65F6 Selenium Grid \u7684\u7EF4\u62A4\u6210\u672C\uFF0C\u6211\u4EEC\u7528 Docker \u5BB9\u5668\u4EE3\u66FF\u4E86\u7ECF\u5178\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u4E2D\u7684\u5B9E\u4F53\u673A/\u865A\u62DF\u673A\uFF0C\u5F62\u6210\u4E86\u57FA\u4E8E Docker \u5B9E\u73B0\u7684 Selenium Grid \u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u3002</p><p>\u800C\u540E\uFF0C\u6211\u4EEC\u53D1\u73B0\u6D4B\u8BD5\u7528\u4F8B\u7684\u6570\u91CF\u8FBE\u5230\u4E00\u5B9A\u89C4\u6A21\u540E\uFF0C\u7BA1\u7406\u548C\u6267\u884C\u53D1\u8D77\u6D4B\u8BD5\u7684 Jenkins Job \u6210\u4E86\u95EE\u9898\u3002\u4E8E\u662F\uFF0C\u6211\u4EEC\u5F15\u5165\u4E86\u4E00\u4E2A\u57FA\u4E8E GUI \u754C\u9762\u7684\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\uFF0C\u5E76\u5728\u5176\u4E0A\u6269\u5C55\u4E86\u8BF8\u5982\u6D4B\u8BD5\u7528\u4F8B\u7248\u672C\u5316\u3001\u63D0\u4F9B\u57FA\u4E8E Restful API \u7684\u6D4B\u8BD5\u6267\u884C\u63A5\u53E3\u7B49\u529F\u80FD\u3002\u4ECE\u800C\uFF0C\u5F62\u6210\u4E86\u7531\u8FD9\u4E2A\u7EDF\u4E00\u6D4B\u8BD5\u6267\u884C\u5E73\u53F0\u53D1\u8D77\u6D4B\u8BD5\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u5F62\u6001\u3002</p><p>\u800C\u4E3A\u4E86\u8FDB\u4E00\u6B65\u89E3\u51B3\u7531\u5355\u4E2A Jenkins \u5E26\u6765\u7684\u7CFB\u7EDF\u74F6\u9888\u95EE\u9898\uFF0C\u6211\u4EEC\u8FC7\u6E21\u5230\u4E86\u57FA\u4E8E Jenkins \u96C6\u7FA4\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\uFF0C\u901A\u8FC7\u591A\u4E2A\u540C\u65F6\u5DE5\u4F5C\u7684 Jenkins Slave\uFF0C\u89E3\u51B3\u4E86\u5927\u91CF\u6D4B\u8BD5\u8BF7\u6C42\u6392\u961F\u7684\u95EE\u9898\u3002</p><p>\u968F\u540E\uFF0C\u4E3A\u4E86\u89E3\u51B3 Selenium Grid \u4E2D Node \u7684\u6570\u91CF\u5230\u5E95\u591A\u5C11\u624D\u5408\u9002\u7684\u95EE\u9898\uFF0C\u6211\u548C\u4F60\u8C08\u8BBA\u4E86\u521B\u65B0\u8BBE\u8BA1\u7684 Selenium Grid \u7684\u81EA\u52A8\u6269\u5BB9\u548C\u6536\u7F29\u6280\u672F\u3002\u81F3\u6B64\uFF0C\u6D4B\u8BD5\u8D1F\u8F7D\u81EA\u9002\u5E94\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u4E5F\u7EC8\u4E8E\u201C\u5343\u547C\u4E07\u5524\u59CB\u51FA\u6765\u201D\u4E86\u3002</p><p>\u6700\u540E\uFF0C\u6211\u8C08\u8BBA\u4E86\u4E0D\u540C\u4F01\u4E1A\u8BE5\u5982\u4F55\u9009\u62E9\u6700\u9002\u5408\u81EA\u5DF1\u7684\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u7684\u95EE\u9898\u3002\u8FD9\u91CC\uFF0C\u6211\u5F3A\u8C03\u4E86\u4E00\u5B9A\u8981\u6839\u636E\u6D4B\u8BD5\u9700\u6C42\u9009\u62E9\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\uFF0C\u800C\u4E0D\u80FD\u4E00\u5473\u5730\u8FFD\u6C42\u6700\u65B0\u7684\u6280\u672F\u3002</p><p>\u6211\u5E0C\u671B\u901A\u8FC7\u8FD9\u79CD\u6388\u4EBA\u4EE5\u6E14\u7684\u65B9\u5F0F\uFF0C\u53EF\u4EE5\u5E2E\u4F60\u62D3\u5BBD\u601D\u8DEF\uFF0C\u5E76\u5C06\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u7684\u8BBE\u8BA1\u601D\u8DEF\u3001\u601D\u60F3\uFF0C\u8FD0\u7528\u5230\u4F60\u7684\u5B9E\u9645\u5DE5\u4F5C\u4E2D\u53BB\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u5176\u5B9E\uFF0C\u5728\u6211\u8BB2\u8FF0\u7684\u8FD9\u4E2A\u6D4B\u8BD5\u57FA\u7840\u67B6\u6784\u7684\u8BBE\u8BA1\u548C\u642D\u5EFA\u8FC7\u7A0B\u4E2D\uFF0C\u8FD8\u6709\u5F88\u591A\u53EF\u4EE5\u4F18\u5316\u548C\u521B\u65B0\u7684\u70B9\u3002\u4F60\u89C9\u5F97\u54EA\u4E9B\u90E8\u5206\u53EF\u4EE5\u518D\u4F18\u5316\u5462\uFF1F\u4F60\u8FD8\u6709\u54EA\u4E9B\u60F3\u6CD5\u5462\uFF1F</p>`,64);function o(r,s){return i}var d=e(n,[["render",o],["__file","41.html.vue"]]);export{d as default};
